/* Color palette: red, black, white only */
* { box-sizing: border-box; }
body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Arial, sans-serif;
  color: #000;
  background: #fff;
  line-height: 1.5;
}
.container { width: min(960px, 92%); margin: 0 auto; }

.hero {
  background: #000;
  color: #fff;
  padding: 4rem 0;
  text-align: center;
  border-bottom: 4px solid #d00000;
}
.hero .subtitle {
  color: #fff;
  max-width: 60ch;
  margin: 0.5rem auto 0;
}

h1, h2 { margin: 0 0 0.5rem; }
.services { margin-top: 2rem; }
.services ul { padding-left: 1.2rem; }
.services li { margin: 0.25rem 0; }

.contact { margin-top: 2rem; }
.field { display: flex; flex-direction: column; margin-bottom: 1rem; }
label { font-weight: 600; }

input, textarea {
  padding: 0.6rem;
  border: 1px solid #000;
  border-radius: 4px;
  background: #fff;
  color: #000;
}
input:focus, textarea:focus { outline: 2px solid #d00000; outline-offset: 2px; }

.btn {
  background: #d00000;
  color: #fff;
  border: none;
  padding: 0.75rem 1rem;
  border-radius: 4px;
  cursor: pointer;
  font-weight: 700;
}
.btn:hover { filter: brightness(0.9); }

.footer {
  border-top: 4px solid #d00000;
  text-align: center;
  padding: 1rem 0;
  margin-top: 3rem;
}

@media (max-width: 600px) {
  .hero { padding: 3rem 0; }
}

document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('contact-form');
  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const nameEl = document.getElementById('name');
      const nameVal = nameEl && 'value' in nameEl ? nameEl.value.trim() : '';
      alert(`Thank you${nameVal ? ', ' + nameVal : ''}! Your message has been received.`);
      form.reset();
    });
  }
});

{
  "name": "lab-technician-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal single-page landing site for a lab technician.",
  "scripts": {
    "test": "jest"
  },
  "devDependencies": {
    "jest": "^29.7.0"
  }
}

const fs = require('fs');
const path = require('path');

describe('index.html', () => {
  test('contains the hero title', () => {
    const html = fs.readFileSync(path.resolve(__dirname, '..', 'index.html'), 'utf8');
    expect(html).toContain('Lab Technician');
  });
});
